class Solution {
    public boolean divisorGame(int n) {
        int count = 0;
        while (n > 0) {
            if (isDivisibleBy(n)) {
                count++;
            }
            n /= 2;
        }
        return count % 2 == 0;
    }

    private boolean isDivisibleBy(int n) {
        for (int i = 2; i * i <= n; i++) {
            if (n % i == 0) {
                return true;
            }
        }
        return false;
    }
}
```

